import org.mockito.ArgumentCaptor;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

/**
 * Unit tests for {@link SemanticQueryService}.
 *
 * <p>
 * Mocks all upstream services so no real HTTP / DB calls are made.
 */
@ExtendWith(MockitoExtension.class)
class SemanticQueryServiceTest {

	private static final UUID TEAM_ID = UUID.randomUUID();
	private static final UUID USER_ID = UUID.randomUUID();
	private static final UUID ORG_ID = UUID.randomUUID();
	private static final String QUESTION = "What did the team commit to last week?";

	private final ObjectMapper objectMapper = new ObjectMapper();

	@Mock
	private PineconeClient pineconeClient;

	@Mock
	private EmbeddingService embeddingService;

	@Mock
	private AiProviderRegistry aiProviderRegistry;

	@Mock
	private AiSuggestionService aiSuggestionService;

	@Mock
	private TeamRepository teamRepo;

	private SemanticQueryService service;

	@BeforeEach
	void setUp() {
		service = new SemanticQueryService(pineconeClient, embeddingService, aiProviderRegistry, aiSuggestionService,
				objectMapper, teamRepo);
	}

	// ── Availability guards ───────────────────────────────────────────────

	@Test
	void query_pineconeUnavailable_returnsUnavailableResult() {
		when(pineconeClient.isAvailable()).thenReturn(false);

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		assertThat(result.available()).isFalse();
		assertThat(result.answer()).isNull();
		verify(embeddingService, never()).embed(anyString());
	}

	@Test
	void query_embeddingUnavailable_returnsUnavailableResult() {
		when(pineconeClient.isAvailable()).thenReturn(true);
		when(embeddingService.isAvailable()).thenReturn(false);

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		assertThat(result.available()).isFalse();
		verify(embeddingService, never()).embed(anyString());
	}

	@Test
	void query_nullQuestion_returnsUnavailableResult() {
		when(pineconeClient.isAvailable()).thenReturn(true);
		when(embeddingService.isAvailable()).thenReturn(true);

		SemanticQueryService.RagQueryResult result = service.query(null, TEAM_ID, USER_ID);

		assertThat(result.available()).isFalse();
	}

	@Test
	void query_blankQuestion_returnsUnavailableResult() {
		when(pineconeClient.isAvailable()).thenReturn(true);
		when(embeddingService.isAvailable()).thenReturn(true);

		SemanticQueryService.RagQueryResult result = service.query("   ", TEAM_ID, USER_ID);

		assertThat(result.available()).isFalse();
	}

	@Test
	void query_embeddingReturnsEmptyVector_returnsUnavailableResult() {
		when(pineconeClient.isAvailable()).thenReturn(true);
		when(embeddingService.isAvailable()).thenReturn(true);
		when(aiProviderRegistry.generateSuggestion(any())).thenReturn(AiSuggestionResult.unavailable());
		when(embeddingService.embed(anyString())).thenReturn(new float[0]);

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		assertThat(result.available()).isFalse();
		verify(pineconeClient, never()).query(anyString(), any(), anyInt(), any());
	}

	// ── Successful pipeline ───────────────────────────────────────────────

	@Test
	void query_successfulPipeline_returnsAvailableResult() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		mockIntentResponse(intentPayload("status_query", null, null, null, List.of("commit")));
		float[] embedding = {0.1f, 0.2f, 0.3f};
		when(embeddingService.embed(QUESTION)).thenReturn(embedding);
		mockPineconeMatches(List.of("commit:uuid-1"), List.of(0.92));
		mockRagAnswer("The team committed to deploying the new API.", 0.9);
		stubSuggestionStore(UUID.randomUUID());

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		assertThat(result.available()).isTrue();
		assertThat(result.answer()).isEqualTo("The team committed to deploying the new API.");
		assertThat(result.confidence()).isEqualTo(0.9);
		assertThat(result.suggestionId()).isNotNull();
	}

	@Test
	void query_successfulPipeline_returnsCorrectSources() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		mockIntentResponse(intentPayload("status_query", null, null, null, List.of("commit")));
		when(embeddingService.embed(QUESTION)).thenReturn(new float[]{0.1f});
		mockPineconeMatches(List.of("commit:uuid-1"), List.of(0.92));
		String answerWithSource = """
				{
				  "answer": "Team committed to API work.",
				  "sources": [
				    {"entityType": "commit", "entityId": "uuid-1", "weekStartDate": "2025-01-06", "snippet": "Deploy new API"}
				  ],
				  "confidence": 0.85
				}
				""";
		when(aiProviderRegistry.generateSuggestion(argOfType(AiContext.TYPE_RAG_QUERY)))
				.thenReturn(new AiSuggestionResult(true, answerWithSource.trim(), "RAG answer", 0.85, "stub-v1"));
		stubSuggestionStore(UUID.randomUUID());

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		assertThat(result.sources()).hasSize(1);
		assertThat(result.sources().get(0).entityType()).isEqualTo("commit");
		assertThat(result.sources().get(0).entityId()).isEqualTo("uuid-1");
		assertThat(result.sources().get(0).weekStartDate()).isEqualTo("2025-01-06");
	}

	// ── Intent failure degrades gracefully ────────────────────────────────

	@Test
	void query_intentClassificationFails_proceedsWithDefaults() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		// Intent returns unavailable
		when(aiProviderRegistry.generateSuggestion(argOfType(AiContext.TYPE_RAG_INTENT)))
				.thenReturn(AiSuggestionResult.unavailable());
		when(embeddingService.embed(QUESTION)).thenReturn(new float[]{0.1f});
		mockPineconeMatches(List.of(), List.of());
		mockRagAnswer("No data found.", 0.3);
		stubSuggestionStore(UUID.randomUUID());

		// Should not throw; should proceed with empty filter defaults
		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		// Pinecone is still called (with default/empty filter)
		verify(pineconeClient).query(anyString(), any(), eq(40), any());
		assertThat(result.available()).isTrue();
	}

	@Test
	void query_intentPayloadUnparseable_proceedsWithDefaults() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		when(aiProviderRegistry.generateSuggestion(argOfType(AiContext.TYPE_RAG_INTENT)))
				.thenReturn(new AiSuggestionResult(true, "not-valid-json", "intent", 0.5, "stub"));
		when(embeddingService.embed(QUESTION)).thenReturn(new float[]{0.1f});
		mockPineconeMatches(List.of(), List.of());
		mockRagAnswer("Answer.", 0.5);
		stubSuggestionStore(UUID.randomUUID());

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		assertThat(result.available()).isTrue();
	}

	// ── Audit storage ─────────────────────────────────────────────────────

	@Test
	void query_successfulResult_storesSuggestionWithCorrectType() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		mockIntentResponse(intentPayload("status_query", null, null, null, List.of("commit")));
		when(embeddingService.embed(QUESTION)).thenReturn(new float[]{0.1f});
		mockPineconeMatches(List.of(), List.of());
		mockRagAnswer("Answer.", 0.8);
		UUID suggestionId = UUID.randomUUID();
		stubSuggestionStore(suggestionId);

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		ArgumentCaptor<String> typeCaptor = ArgumentCaptor.forClass(String.class);
		verify(aiSuggestionService).storeSuggestion(typeCaptor.capture(), eq(USER_ID), isNull(), isNull(), anyString(),
				any(AiSuggestionResult.class));
		assertThat(typeCaptor.getValue()).isEqualTo(AiContext.TYPE_RAG_QUERY);
		assertThat(result.suggestionId()).isEqualTo(suggestionId);
	}

	@Test
	void query_suggestionStoreFails_stillReturnsResult() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		mockIntentResponse(intentPayload("status_query", null, null, null, List.of()));
		when(embeddingService.embed(QUESTION)).thenReturn(new float[]{0.1f});
		mockPineconeMatches(List.of(), List.of());
		mockRagAnswer("Answer.", 0.7);
		when(aiSuggestionService.storeSuggestion(anyString(), any(), any(), any(), anyString(), any()))
				.thenThrow(new RuntimeException("DB error"));

		SemanticQueryService.RagQueryResult result = service.query(QUESTION, TEAM_ID, USER_ID);

		assertThat(result.available()).isTrue();
		assertThat(result.suggestionId()).isNull();
	}

	// ── Namespace resolution ──────────────────────────────────────────────

	@Test
	void query_usesOrgIdAsNamespace() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		mockIntentResponse(intentPayload("general_query", null, null, null, List.of()));
		when(embeddingService.embed(QUESTION)).thenReturn(new float[]{0.1f});
		when(pineconeClient.query(anyString(), any(), anyInt(), any())).thenReturn(List.of());
		mockRagAnswer("Answer.", 0.5);
		stubSuggestionStore(UUID.randomUUID());

		service.query(QUESTION, TEAM_ID, USER_ID);

		ArgumentCaptor<String> namespaceCaptor = ArgumentCaptor.forClass(String.class);
		verify(pineconeClient).query(namespaceCaptor.capture(), any(), anyInt(), any());
		assertThat(namespaceCaptor.getValue()).isEqualTo(ORG_ID.toString());
	}

	@Test
	@SuppressWarnings("unchecked")
	void query_intentFiltersApplyUserAndDateRangeToPineconeQuery() throws Exception {
		setUpAvailableServices();
		setUpTeam();
		mockIntentResponse(intentPayload("general_query", "self", "2025-01-06", "2025-01-31", List.of("commit")));
		when(embeddingService.embed(QUESTION)).thenReturn(new float[]{0.1f});
		when(pineconeClient.query(anyString(), any(), anyInt(), any())).thenReturn(List.of());
		mockRagAnswer("Answer.", 0.5);
		stubSuggestionStore(UUID.randomUUID());

		service.query(QUESTION, TEAM_ID, USER_ID);

		ArgumentCaptor<Map<String, Object>> filterCaptor = ArgumentCaptor.forClass(Map.class);
		verify(pineconeClient).query(anyString(), any(), eq(40), filterCaptor.capture());
		Map<String, Object> filter = filterCaptor.getValue();
		assertThat(filter.get("teamId")).isEqualTo(TEAM_ID.toString());
		assertThat(filter.get("userId")).isEqualTo(USER_ID.toString());
		// entityType is now filtered by exact string match (single type)
		assertThat(filter.get("entityType")).isEqualTo("commit");
		// date range is now stored as numeric epoch days
		@SuppressWarnings("unchecked")
		Map<String, Object> epochRange = (Map<String, Object>) filter.get("weekStartEpochDay");
		assertThat(epochRange).isNotNull();
		assertThat((Long) epochRange.get("$gte")).isEqualTo(java.time.LocalDate.parse("2025-01-06").toEpochDay());
		assertThat((Long) epochRange.get("$lte")).isEqualTo(java.time.LocalDate.parse("2025-01-31").toEpochDay());
	}

	// ── Helpers ───────────────────────────────────────────────────────────

	private void setUpAvailableServices() {
		when(pineconeClient.isAvailable()).thenReturn(true);
		when(embeddingService.isAvailable()).thenReturn(true);
	}

	private void setUpTeam() {
		Team team = new Team();
		team.setId(TEAM_ID);
		team.setOrganizationId(ORG_ID);
		when(teamRepo.findById(TEAM_ID)).thenReturn(Optional.of(team));
	}

	private void mockIntentResponse(String payload) {
		when(aiProviderRegistry.generateSuggestion(argOfType(AiContext.TYPE_RAG_INTENT)))
				.thenReturn(new AiSuggestionResult(true, payload, "intent", 0.9, "stub-v1"));
	}

	private void mockRagAnswer(String answer, double confidence) throws Exception {
		String payload = objectMapper
				.writeValueAsString(Map.of("answer", answer, "sources", List.of(), "confidence", confidence));
		when(aiProviderRegistry.generateSuggestion(argOfType(AiContext.TYPE_RAG_QUERY)))
				.thenReturn(new AiSuggestionResult(true, payload, "rag answer", confidence, "stub-v1"));
	}

	private void mockPineconeMatches(List<String> ids, List<Double> scores) {
		List<PineconeClient.PineconeMatch> matches = new java.util.ArrayList<>();
		for (int i = 0; i < ids.size(); i++) {
			matches.add(new PineconeClient.PineconeMatch(ids.get(i), scores.get(i), Map.of()));
		}
		when(pineconeClient.query(anyString(), any(), anyInt(), any())).thenReturn(matches);
	}

	private void stubSuggestionStore(UUID suggestionId) {
		AiSuggestion stored = new AiSuggestion();
		stored.setId(suggestionId);
		when(aiSuggestionService.storeSuggestion(anyString(), any(), any(), any(), anyString(), any()))
				.thenReturn(stored);
	}

	private static String intentPayload(String intent, String userFilter, String from, String to,
			List<String> entityTypes) throws Exception {
		Map<String, Object> payload = new java.util.LinkedHashMap<>();
		payload.put("intent", intent);
		payload.put("userFilter", userFilter);
		payload.put("entityTypes", entityTypes);
		payload.put("keywords", List.of());
		if (from != null || to != null) {
			payload.put("timeRange", Map.of("from", from, "to", to));
		} else {
			payload.put("timeRange", null);
		}
		return new ObjectMapper().writeValueAsString(payload);
	}

	/** Matches an AiContext by its suggestionType for Mockito. */
	private static AiContext argOfType(String type) {
		return org.mockito.ArgumentMatchers.argThat(ctx -> ctx != null && type.equals(ctx.suggestionType()));
	}
}

package com.weeklycommit.ai.dto;

import java.util.List;
import java.util.UUID;

/**
 * Response from the {@code POST /api/ai/query} RAG endpoint.
 *
 * @param aiAvailable
 *            {@code false} when the RAG pipeline is unavailable (Pinecone or
 *            LLM down); all other fields are meaningless in that case
 * @param answer
 *            synthesised natural-language answer (null when unavailable)
 * @param sources
 *            source chunks that informed the answer
 * @param confidence
 *            model confidence [0.0, 1.0]
 * @param suggestionId
 *            ID of the persisted
 *            {@link com.weeklycommit.domain.entity.AiSuggestion} audit row
 *            (null when unavailable)
 */
public record RagQueryResponse(boolean aiAvailable, String answer, List<RagSourceDto> sources, double confidence,
		UUID suggestionId) {

	/** Convenience factory for a degraded/unavailable response. */
	public static RagQueryResponse unavailable() {
		return new RagQueryResponse(false, null, List.of(), 0.0, null);
	}
}

/**
 * RAG (Retrieval-Augmented Generation) API client functions.
 * Covers the semantic query endpoint and AI insight retrieval endpoints.
 */
import type { ApiClient } from "./client.js";

// ── Types ─────────────────────────────────────────────────────────────────────

export interface RagQueryRequest {
  question: string;
  teamId?: string;
  userId?: string;
}

export interface RagSource {
  entityType: string;
  entityId: string;
  weekStartDate?: string;
  snippet?: string;
}

export interface RagQueryResponse {
  aiAvailable: boolean;
  answer?: string;
  sources?: RagSource[];
  confidence?: number;
  suggestionId?: string;
}

export interface InsightCard {
  suggestionId: string;
  insightText: string;
  severity: string;
  sourceEntityIds: string[];
  actionSuggestion: string;
  createdAt: string;
}

export interface InsightListResponse {
  aiAvailable: boolean;
  insights: InsightCard[];
}

// ── API factory ───────────────────────────────────────────────────────────────

export function createRagApi(client: ApiClient, _actorUserId: string) {
  return {
    /**
     * POST /api/ai/query — execute a semantic RAG query against indexed planning
     * data. Returns an AI-synthesised answer with source citations.
     */
    submitQuery: (req: RagQueryRequest): Promise<RagQueryResponse> =>
      client.post("/ai/query", req),

    /**
     * GET /api/teams/{id}/week/{weekStart}/ai-insights — retrieve persisted
     * TEAM_INSIGHT rows for the given team and week.
     *
     * @param teamId    team UUID string
     * @param weekStart ISO date string (YYYY-MM-DD) for the Monday of the week
     */
    getTeamInsights: (
      teamId: string,
      weekStart: string,
    ): Promise<InsightListResponse> =>
      client.get(
        `/teams/${encodeURIComponent(teamId)}/week/${encodeURIComponent(weekStart)}/ai-insights`,
      ),

    /**
     * GET /api/plans/{id}/ai-insights — retrieve persisted PERSONAL_INSIGHT rows
     * for the given plan.
     *
     * @param planId plan UUID string
     */
    getPlanInsights: (planId: string): Promise<InsightListResponse> =>
      client.get(`/plans/${encodeURIComponent(planId)}/ai-insights`),
  };
}

export type RagApi = ReturnType<typeof createRagApi>;

/**
 * React hooks for RAG (Retrieval-Augmented Generation) API endpoints.
 */
import { useCallback, useMemo, useState } from "react";
import { useHostBridge } from "../host/HostProvider.js";
import { createApiClient } from "./client.js";
import { useQuery, type QueryState } from "./hooks.js";
import {
  createRagApi,
  type InsightListResponse,
  type RagApi,
  type RagQueryResponse,
} from "./ragApi.js";

// ── Base hook ─────────────────────────────────────────────────────────────────

/** Returns a stable {@link RagApi} instance bound to the current user. */
export function useRagApi(): RagApi {
  const bridge = useHostBridge();
  const { authToken, authenticatedUser } = bridge.context;
  return useMemo(() => {
    const client = createApiClient({
      baseUrl: "/api",
      getAuthToken: () => bridge.context.authToken,
    });
    return createRagApi(client, authenticatedUser.id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [authToken, authenticatedUser.id]);
}

// ── Query hooks ───────────────────────────────────────────────────────────────

/**
 * Fetches TEAM_INSIGHT cards for the given team and week.
 *
 * @param teamId    team UUID string, or {@code null} to skip fetching
 * @param weekStart ISO date string (YYYY-MM-DD) for the Monday of the target week
 */
export function useTeamInsights(
  teamId: string | null,
  weekStart: string,
): QueryState<InsightListResponse> {
  const api = useRagApi();
  return useQuery<InsightListResponse>(
    `team-insights-${teamId ?? "none"}-${weekStart}`,
    () => {
      if (!teamId) return Promise.reject(new Error("No team ID"));
      return api.getTeamInsights(teamId, weekStart);
    },
    { enabled: teamId != null },
  );
}

/**
 * Fetches PERSONAL_INSIGHT cards for the given plan.
 *
 * @param planId plan UUID string, or {@code null} to skip fetching
 */
export function usePlanInsights(
  planId: string | null,
): QueryState<InsightListResponse> {
  const api = useRagApi();
  return useQuery<InsightListResponse>(
    `plan-insights-${planId ?? "none"}`,
    () => {
      if (!planId) return Promise.reject(new Error("No plan ID"));
      return api.getPlanInsights(planId);
    },
    { enabled: planId != null },
  );
}

// ── Mutation hook ─────────────────────────────────────────────────────────────

export interface SemanticQueryState {
  /** Executes the RAG query. */
  mutate: (question: string, teamId?: string, userId?: string) => Promise<void>;
  /** The most recent query response; {@code undefined} before first call. */
  data: RagQueryResponse | undefined;
  /** {@code true} while a query is in-flight. */
  loading: boolean;
  /** Error message if the last query failed. */
  error: string | null;
}

/**
 * Mutation hook for submitting a semantic RAG query.
 *
 * @example
 * ```tsx
 * const { mutate, data, loading, error } = useSemanticQuery();
 *
 * const handleSearch = (question: string) => {
 *   mutate(question, teamId, userId);
 * };
 * ```
 */
export function useSemanticQuery(): SemanticQueryState {
  const api = useRagApi();
  const [data, setData] = useState<RagQueryResponse | undefined>(undefined);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const mutate = useCallback(
    async (question: string, teamId?: string, userId?: string) => {
      setLoading(true);
      setError(null);
      try {
        const result = await api.submitQuery({
          question,
          ...(teamId !== undefined && { teamId }),
          ...(userId !== undefined && { userId }),
        });
        setData(result);
      } catch (err: unknown) {
        setError(err instanceof Error ? err.message : "Unexpected error");
        setData(undefined);
      } finally {
        setLoading(false);
      }
    },
    [api],
  );

  return { mutate, data, loading, error };
}

/**
 * QueryAnswerCard — displays a RAG-generated answer with rich formatting,
 * source citations, a confidence indicator, and AI feedback buttons.
 */
import { useState } from "react";
import {
  ChevronDown,
  ChevronRight,
  ExternalLink,
  FileText,
  Ticket,
  ArrowRightLeft,
  MessageSquare,
  Bot,
} from "lucide-react";
import { Badge } from "../ui/Badge.js";
import {
  Card,
  CardContent,
  CardFooter,
  CardHeader,
  CardTitle,
} from "../ui/Card.js";
import { cn } from "../../lib/utils.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import { AnswerRenderer } from "./AnswerRenderer.js";
import type { RagSource } from "../../api/ragApi.js";

// ── Confidence indicator ──────────────────────────────────────────────────────

function confidenceLabel(confidence: number): string {
  if (confidence >= 0.8) return "High";
  if (confidence >= 0.5) return "Medium";
  return "Low";
}

function confidenceCls(confidence: number): string {
  if (confidence >= 0.8) return "text-foreground font-bold";
  if (confidence >= 0.5) return "text-muted";
  return "text-foreground underline";
}

function confidenceBarCls(confidence: number): string {
  if (confidence >= 0.8) return "bg-foreground";
  if (confidence >= 0.5) return "bg-foreground/40";
  return "bg-foreground/20";
}

// ── Source icon ───────────────────────────────────────────────────────────────

function sourceIcon(entityType: string) {
  switch (entityType) {
    case "commit":
    case "plan_summary":
      return FileText;
    case "ticket":
      return Ticket;
    case "scope_change":
      return ArrowRightLeft;
    case "carry_forward":
      return ArrowRightLeft;
    case "manager_comment":
      return MessageSquare;
    default:
      return FileText;
  }
}

// ── Source citation ───────────────────────────────────────────────────────────

function SourceCitation({ source }: { source: RagSource }) {
  const { entityType, entityId, weekStartDate, snippet } = source;
  const Icon = sourceIcon(entityType);

  let link: string | null = null;
  if (entityType === "ticket") link = "/tickets";

  const label =
    entityType === "carry_forward"
      ? "carry-forward"
      : entityType.replace(/_/g, " ");

  return (
    <li
      className="flex items-start gap-2 text-xs rounded-default border border-border/50 bg-surface-raised px-2.5 py-2"
      data-testid={`rag-source-${entityId}`}
    >
      <Icon className="h-3.5 w-3.5 mt-0.5 shrink-0 text-muted" aria-hidden="true" />
      <span className="flex-1 min-w-0">
        <span className="flex items-center gap-1.5 flex-wrap">
          <Badge variant="default" className="text-[0.6rem] capitalize">
            {label}
          </Badge>
          {weekStartDate && (
            <span className="text-[0.65rem] text-muted tabular-nums">w/{weekStartDate}</span>
          )}
        </span>
        {snippet && (
          <span className="block text-[0.65rem] text-muted mt-1 leading-relaxed">
            &ldquo;{snippet}&rdquo;
          </span>
        )}
        {link && (
          <a
            href={link}
            className="inline-flex items-center gap-0.5 text-primary hover:underline text-[0.65rem] mt-0.5"
            target="_blank"
            rel="noreferrer"
            data-testid={`rag-source-link-${entityId}`}
          >
            view <ExternalLink className="h-2.5 w-2.5" />
          </a>
        )}
      </span>
    </li>
  );
}

// ── Main component ────────────────────────────────────────────────────────────

interface QueryAnswerCardProps {
  answer: string;
  sources: RagSource[];
  confidence: number;
  suggestionId: string;
  className?: string;
}

export function QueryAnswerCard({
  answer,
  sources,
  confidence,
  suggestionId,
  className,
}: QueryAnswerCardProps) {
  const pct = Math.round(Math.max(0, Math.min(1, confidence)) * 100);
  const [sourcesExpanded, setSourcesExpanded] = useState(false);

  return (
    <Card className={cn("w-full", className)} data-testid="query-answer-card">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-sm">
          <Bot className="h-4 w-4 text-primary" />
          AI Answer
        </CardTitle>
        {/* Confidence indicator */}
        <div
          className="flex items-center gap-1.5"
          data-testid="confidence-indicator"
        >
          <span
            className={cn(
              "text-xs font-semibold",
              confidenceCls(confidence),
            )}
          >
            {confidenceLabel(confidence)}
          </span>
          <div
            className="h-1.5 w-16 bg-border overflow-hidden"
            aria-label={`Confidence: ${pct}%`}
            title={`Confidence: ${pct}%`}
          >
            <div
              className={cn("h-full", confidenceBarCls(confidence))}
              style={{ width: `${pct}%` }}
              data-testid="confidence-bar"
            />
          </div>
          <span className="text-[0.65rem] text-muted tabular-nums">{pct}%</span>
        </div>
      </CardHeader>

      <CardContent className="flex flex-col gap-3">
        {/* Rich answer text */}
        <AnswerRenderer text={answer} />

        {/* Source citations — collapsible */}
        {sources.length > 0 && (
          <div data-testid="rag-sources-section">
            <button
              type="button"
              onClick={() => setSourcesExpanded((v) => !v)}
              className="flex items-center gap-1 text-[0.65rem] font-semibold text-muted uppercase tracking-wider hover:text-foreground transition-colors cursor-pointer bg-transparent border-none p-0"
              aria-expanded={sourcesExpanded}
              data-testid="rag-sources-toggle"
            >
              {sourcesExpanded ? (
                <ChevronDown className="h-3 w-3" />
              ) : (
                <ChevronRight className="h-3 w-3" />
              )}
              Sources ({sources.length})
            </button>
            {sourcesExpanded && (
              <ul className="flex flex-col gap-1.5 list-none m-0 p-0 mt-2">
                {sources.map((s) => (
                  <SourceCitation key={`${s.entityType}-${s.entityId}`} source={s} />
                ))}
              </ul>
            )}
          </div>
        )}
      </CardContent>

      <CardFooter className="justify-between">
        <span className="text-[0.65rem] text-muted">
          AI-generated answer — verify before acting
        </span>
        <AiFeedbackButtons suggestionId={suggestionId} />
      </CardFooter>
    </Card>
  );
}

/**
 * SemanticSearchInput — text input + submit that executes a RAG query
 * and renders the answer in a QueryAnswerCard below the input.
 */
import { useCallback, useRef, useState } from "react";
import { Bot, RotateCcw, Search, MessageCircle } from "lucide-react";
import { Button } from "../ui/Button.js";
import { Input } from "../ui/Input.js";

import { cn } from "../../lib/utils.js";
import { useSemanticQuery } from "../../api/ragHooks.js";
import { QueryAnswerCard } from "./QueryAnswerCard.js";

const SUGGESTED_QUESTIONS = [
  "What did the team commit to last week?",
  "Which RCDOs received the most effort this month?",
  "What are the recurring carry-forward patterns?",
  "Which team members are overcommitting?",
  "What KING/QUEEN work was achieved last week?",
] as const;

interface SemanticSearchInputProps {
  teamId?: string;
  userId?: string;
  className?: string;
}

export function SemanticSearchInput({
  teamId,
  userId,
  className,
}: SemanticSearchInputProps) {
  const [question, setQuestion] = useState("");
  const { mutate, data, loading, error } = useSemanticQuery();
  const inputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = useCallback(
    async (e: React.FormEvent) => {
      e.preventDefault();
      const q = question.trim();
      if (!q) return;
      await mutate(q, teamId, userId);
    },
    [question, mutate, teamId, userId],
  );

  const handleRetry = useCallback(() => {
    const q = question.trim();
    if (!q) return;
    void mutate(q, teamId, userId);
  }, [question, mutate, teamId, userId]);

  return (
    <div className={cn("rounded-default border border-border bg-surface p-4 flex flex-col gap-3", className)}>
      {/* Header + form on one line */}
      <div className="flex items-center gap-2">
        <Bot className="h-4 w-4 text-primary shrink-0" aria-hidden="true" />
        <span className="text-sm font-semibold text-foreground whitespace-nowrap">
          Ask AI about your team&apos;s work
        </span>
      </div>

      <form onSubmit={(e) => void handleSubmit(e)} className="flex gap-2">
        <Input
          ref={inputRef}
          data-testid="semantic-search-input"
          value={question}
          onChange={(e) => setQuestion(e.target.value)}
          placeholder="e.g. What did the team commit to last week?"
          icon={<Search className="h-3.5 w-3.5" />}
          disabled={loading}
          className="flex-1"
          aria-label="Ask a question about your team's work history"
        />
        <Button
          type="submit"
          variant="primary"
          size="md"
          disabled={loading || question.trim().length === 0}
          data-testid="semantic-search-submit"
          aria-label="Submit question"
        >
          {loading ? (
            <span className="inline-flex items-center gap-1.5">
              <span
                className="h-3.5 w-3.5 rounded-full border-2 border-white/30 border-t-white animate-spin"
                aria-hidden="true"
              />
              Searching…
            </span>
          ) : (
            <>
              <Search className="h-3.5 w-3.5" />
              Search
            </>
          )}
        </Button>
      </form>

      {/* Suggested questions — shown when input is empty and no result */}
      {!question.trim() && !data && !loading && !error && (
        <div className="flex flex-wrap gap-1.5" data-testid="suggested-questions">
          <span className="text-[0.65rem] text-muted flex items-center gap-1 mr-1">
            <MessageCircle className="h-3 w-3" /> Try asking:
          </span>
          {SUGGESTED_QUESTIONS.map((q) => (
            <button
              key={q}
              type="button"
              onClick={() => {
                setQuestion(q);
                void mutate(q, teamId, userId);
              }}
              className="inline-flex items-center rounded-full border border-primary/20 bg-primary/5 px-2.5 py-1 text-[0.65rem] text-primary hover:bg-primary/10 hover:border-primary/40 transition-colors cursor-pointer"
              data-testid={`suggested-q-${q.slice(0, 20).replace(/\s/g, "-").toLowerCase()}`}
            >
              {q}
            </button>
          ))}
        </div>
      )}

      {/* Loading state */}
      {loading && (
        <div
          className="flex items-center gap-2 text-sm text-muted animate-pulse"
          data-testid="semantic-search-loading"
          role="status"
          aria-live="polite"
        >
          <Bot className="h-4 w-4 shrink-0" aria-hidden="true" />
          Searching your team&apos;s planning history…
        </div>
      )}

      {/* Error state */}
      {!loading && error && (
        <div
          className="flex items-center justify-between gap-2 rounded-default border border-danger/30 bg-danger/5 px-3 py-2.5"
          data-testid="semantic-search-error"
          role="alert"
        >
          <span className="text-sm text-danger">{error}</span>
          <Button
            variant="ghost"
            size="sm"
            onClick={handleRetry}
            data-testid="semantic-search-retry"
            aria-label="Retry search"
          >
            <RotateCcw className="h-3.5 w-3.5" />
            Retry
          </Button>
        </div>
      )}

      {/* Answer card */}
      {!loading && !error && data?.aiAvailable && data.answer && (
        <QueryAnswerCard
          answer={data.answer}
          sources={data.sources ?? []}
          confidence={data.confidence ?? 0}
          suggestionId={data.suggestionId ?? ""}
          data-testid="semantic-search-answer"
        />
      )}

      {/* AI unavailable (no Pinecone / LLM) */}
      {!loading && !error && data && !data.aiAvailable && (
        <div
          className="flex items-start gap-2 rounded-default border border-dashed border-border bg-background/60 px-3 py-2.5 text-xs text-muted"
          data-testid="semantic-search-unavailable"
        >
          <Bot className="h-3.5 w-3.5 mt-0.5 shrink-0" aria-hidden="true" />
          <span>
            AI search requires the vector index to be configured and populated.
            Go to <strong>Admin → Reindex</strong> to build the search index, or
            ensure <code>PINECONE_API_KEY</code> is set.
          </span>
        </div>
      )}
    </div>
  );
}

