/**
 * What-If Planner API client functions.
 * Simulates hypothetical plan mutations in-memory and returns structured
 * impact analysis with an optional LLM narrative.
 */
import type { ApiClient } from "./client.js";

// ── Types ─────────────────────────────────────────────────────────────────────

export type WhatIfMutationAction =
  | "ADD_COMMIT"
  | "REMOVE_COMMIT"
  | "MODIFY_COMMIT";

export interface WhatIfMutation {
  action: WhatIfMutationAction;
  /** Commit id to remove or modify (null for ADD_COMMIT). */
  commitId?: string;
  /** Draft title (used for ADD_COMMIT or MODIFY_COMMIT). */
  title?: string;
  /** Chess piece name as plain string (e.g. "KING"). */
  chessPiece?: string;
  /** Estimated story points. */
  estimatePoints?: number;
  /** RCDO node id. */
  rcdoNodeId?: string;
}

export interface WhatIfRequest {
  planId: string;
  userId: string;
  hypotheticalChanges: WhatIfMutation[];
}

/** Snapshot of plan state at a point in time. */
export interface PlanSnapshot {
  totalPoints: number;
  capacityBudget: number;
  /** Active risk signal types, e.g. "OVERCOMMIT". */
  riskSignals: string[];
  /** Map of RCDO node id → total planned points for that node. */
  rcdoCoverage: Record<string, number>;
}

/** Change in story-point coverage for a single RCDO node. */
export interface RcdoCoverageChange {
  rcdoNodeId: string;
  /** RCDO node title (null if not resolved). */
  rcdoTitle?: string | null;
  beforePoints: number;
  afterPoints: number;
}

/** Risk signals added or resolved by mutations. */
export interface RiskDelta {
  newRisks: string[];
  resolvedRisks: string[];
}

/** Response from POST /api/ai/what-if. */
export interface WhatIfResponse {
  /** false when the simulation is unavailable. */
  available: boolean;
  /** Plan state before mutations. */
  currentState: PlanSnapshot | null;
  /** Plan state after mutations. */
  projectedState: PlanSnapshot | null;
  /** Change in total points: projected − current. */
  capacityDelta: number;
  /** Per-RCDO-node point changes. */
  rcdoCoverageChanges: RcdoCoverageChange[] | null;
  /** Risk signal additions and removals. */
  riskDelta: RiskDelta | null;
  /** LLM narrative (null when AI is unavailable). */
  narrative?: string | null;
  /** LLM recommendation (null when AI is unavailable). */
  recommendation?: string | null;
}

// ── API factory ───────────────────────────────────────────────────────────────

export function createWhatIfApi(client: ApiClient, _actorUserId: string) {
  return {
    /**
     * POST /api/ai/what-if — simulates hypothetical commit mutations in-memory
     * and returns structured before/after impact analysis. Always returns
     * structured data; narrative/recommendation are null when AI is down.
     */
    simulate: (req: WhatIfRequest): Promise<WhatIfResponse> =>
      client.post("/ai/what-if", req),
  };
}

export type WhatIfApi = ReturnType<typeof createWhatIfApi>;

/**
 * ProactiveRiskBanner — displays critical AI-detected risk signals as
 * prominent, persistent banners on the IC's own My Week page.
 *
 * The parent (MyWeek) is responsible for only rendering this component
 * when the plan is LOCKED. Risk signals are filtered to the three critical
 * types that warrant immediate IC attention:
 *   OVERCOMMIT, BLOCKED_CRITICAL, REPEATED_CARRY_FORWARD
 *
 * Non-critical types (UNDERCOMMIT, SCOPE_VOLATILITY) are excluded — they
 * are surfaced on the Team Week risk tab instead.
 */
import { useEffect } from "react";
import { AlertTriangle, ShieldAlert, TrendingDown, RotateCcw } from "lucide-react";
import { cn } from "../../lib/utils.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import { useRiskSignals } from "../../api/aiHooks.js";
import type { RiskSignal } from "../../api/aiApi.js";

// ── Critical signal type filter ───────────────────────────────────────────────

/** Signal types shown as proactive IC banners on My Week. */
const CRITICAL_SIGNAL_TYPES = new Set([
  "OVERCOMMIT",
  "BLOCKED_CRITICAL",
  "REPEATED_CARRY_FORWARD",
]);

// ── Per-type display config ───────────────────────────────────────────────────

interface SignalConfig {
  Icon: typeof AlertTriangle;
  /** Tailwind border + background classes for the banner. */
  cls: string;
  /** Short actionable hint shown below the rationale. */
  actionHint: string;
}

const SIGNAL_CONFIG: Record<string, SignalConfig> = {
  OVERCOMMIT: {
    Icon: TrendingDown,
    cls: "border-warning-border bg-warning-bg",
    actionHint: "Consider reducing scope before the week runs out.",
  },
  BLOCKED_CRITICAL: {
    Icon: ShieldAlert,
    cls: "border-danger-border bg-danger-bg",
    actionHint: "Resolve the blocked ticket or escalate to your manager.",
  },
  REPEATED_CARRY_FORWARD: {
    Icon: RotateCcw,
    cls: "border-warning-border bg-warning-bg",
    actionHint:
      "Review whether this work needs to be broken down or deprioritised.",
  },
};

// ── Individual banner ─────────────────────────────────────────────────────────

function RiskBannerItem({ signal }: { signal: RiskSignal }) {
  const config = SIGNAL_CONFIG[signal.signalType];
  const Icon = config?.Icon ?? AlertTriangle;
  const cls = config?.cls ?? "border-border bg-background";
  const actionHint = config?.actionHint;

  return (
    <div
      className={cn(
        "rounded-default border px-4 py-3 flex items-start gap-3",
        cls,
      )}
      role="alert"
      data-testid={`risk-banner-${signal.id}`}
    >
      <Icon
        className="h-4 w-4 mt-0.5 shrink-0 text-foreground"
        aria-hidden="true"
      />
      <div className="flex-1 min-w-0">
        <div className="flex items-start justify-between gap-2">
          <div className="flex-1 min-w-0">
            <p
              className="m-0 text-sm font-semibold text-foreground"
              data-testid={`risk-banner-type-${signal.id}`}
            >
              {signal.signalType.replace(/_/g, " ")}
            </p>
            <p
              className="m-0 text-sm text-foreground leading-relaxed mt-0.5"
              data-testid={`risk-banner-rationale-${signal.id}`}
            >
              {signal.rationale}
            </p>
            {actionHint && (
              <p
                className="m-0 text-xs text-muted italic mt-1"
                data-testid={`risk-banner-action-${signal.id}`}
              >
                → {actionHint}
              </p>
            )}
          </div>
          {/* signal.id is the AiSuggestion PK — suitable as feedback target */}
          <AiFeedbackButtons suggestionId={signal.id} />
        </div>
      </div>
    </div>
  );
}

// ── Main component ────────────────────────────────────────────────────────────

interface ProactiveRiskBannerProps {
  /** Plan UUID. The parent must only render this for LOCKED plans. */
  planId: string;
  /**
   * Called once the signal data is resolved with the count of critical signals
   * (0 when no critical signals, or when AI is unavailable/errored).
   * Useful for the parent to show a count badge or hide the section.
   */
  onSignalCount?: (count: number) => void;
}

/**
 * Renders zero or more alert banners for critical AI risk signals.
 * Returns `null` when AI is unavailable, loading, errored, or when no
 * critical signals exist — so callers need no conditional guard.
 */
export function ProactiveRiskBanner({ planId, onSignalCount }: ProactiveRiskBannerProps) {
  const { data, loading, error } = useRiskSignals(planId);

  const criticalSignals = (!loading && !error && data?.aiAvailable)
    ? data.signals.filter((s) => CRITICAL_SIGNAL_TYPES.has(s.signalType))
    : [];

  // Report count to parent after data resolves (not during render).
  useEffect(() => {
    if (loading) return;
    onSignalCount?.(criticalSignals.length);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [loading, criticalSignals.length]);

  // Keep the UI clean: no loading skeleton for proactive banners.
  if (loading) return null;

  // Silently degrade when AI is unavailable or the fetch failed.
  if (error || !data?.aiAvailable) return null;

  if (criticalSignals.length === 0) return null;

  return (
    <div
      className="flex flex-col gap-2"
      data-testid="proactive-risk-banners"
      aria-label="Active risk signals"
    >
      {criticalSignals.map((signal) => (
        <RiskBannerItem key={signal.id} signal={signal} />
      ))}
    </div>
  );
}

/**
 * Thumbs up / thumbs down feedback buttons for AI suggestions.
 * Records feedback via POST /api/ai/feedback.
 */
import { useState, useCallback } from "react";
import { ThumbsUp, ThumbsDown } from "lucide-react";
import { Button } from "../ui/Button.js";
import { cn } from "../../lib/utils.js";
import { useAiApi } from "../../api/aiHooks.js";
import { useHostBridge } from "../../host/HostProvider.js";
import type { FeedbackAction } from "../../api/aiApi.js";

interface AiFeedbackButtonsProps {
  suggestionId: string;
  className?: string;
}

export function AiFeedbackButtons({ suggestionId, className }: AiFeedbackButtonsProps) {
  const aiApi = useAiApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const [submitted, setSubmitted] = useState<FeedbackAction | null>(null);

  const handleFeedback = useCallback(
    async (action: FeedbackAction) => {
      try {
        await aiApi.recordFeedback({ suggestionId, userId, action });
        setSubmitted(action);
      } catch {
        // Non-critical — don't block the UI
      }
    },
    [aiApi, suggestionId, userId],
  );

  if (submitted) {
    return (
      <span className={cn("text-xs text-muted italic", className)}>
        {submitted === "ACCEPTED" ? "Thanks! 👍" : "Noted 👎"}
      </span>
    );
  }

  return (
    <span className={cn("inline-flex gap-1", className)}>
      <Button
        variant="ghost"
        size="icon"
        onClick={() => void handleFeedback("ACCEPTED")}
        aria-label="Helpful suggestion"
        className="h-6 w-6 text-muted hover:text-foreground"
        data-testid="ai-feedback-accept"
      >
        <ThumbsUp className="h-3.5 w-3.5" />
      </Button>
      <Button
        variant="ghost"
        size="icon"
        onClick={() => void handleFeedback("DISMISSED")}
        aria-label="Not helpful"
        className="h-6 w-6 text-muted hover:text-foreground"
        data-testid="ai-feedback-dismiss"
      >
        <ThumbsDown className="h-3.5 w-3.5" />
      </Button>
    </span>
  );
}

import { useState, useCallback } from "react";

/**
 * Tracks how many times a user has dismissed a specific AI component.
 *
 * After `threshold` consecutive dismissals the hook reports
 * `shouldAutoCollapse: true` so callers can default the component to
 * collapsed without the user having to dismiss it again.
 *
 * Usage:
 *   const { shouldAutoCollapse, recordDismiss } = useDismissMemory("ai-lint");
 */
export function useDismissMemory(
  componentId: string,
  threshold = 3,
): { shouldAutoCollapse: boolean; recordDismiss: () => void } {
  const key = `wc-dismiss-${componentId}`;

  const [count, setCount] = useState<number>(() => {
    try {
      return parseInt(localStorage.getItem(key) ?? "0", 10) || 0;
    } catch {
      return 0;
    }
  });

  const shouldAutoCollapse = count >= threshold;

  const recordDismiss = useCallback(() => {
    const next = count + 1;
    setCount(next);
    try {
      localStorage.setItem(key, String(next));
    } catch {
      // Silently ignore — localStorage may be unavailable.
    }
  }, [count, key]);

  return { shouldAutoCollapse, recordDismiss };
}

