package com.weeklycommit.ai.provider;

/**
 * Result returned by an {@link AiProvider}.
 *
 * <p>
 * When {@code available} is {@code false}, all other fields are meaningless and
 * callers should propagate {@code aiAvailable: false} to their response without
 * failing the request.
 */
public record AiSuggestionResult(
		/** {@code false} when the provider is down or AI is disabled. */
		boolean available,
		/**
		 * JSON-serialised suggestion payload. Structure varies by
		 * {@link AiContext#suggestionType()}.
		 */
		String payload,
		/** Human-readable rationale explaining why the suggestion was made. */
		String rationale,
		/**
		 * Provider confidence in the primary suggestion [0.0, 1.0]. Used for RCDO
		 * suggestions to filter below the surfacing threshold.
		 */
		double confidence,
		/** Provider model identifier for audit and reproducibility. */
		String modelVersion,
		/**
		 * Prompt template version identifier for A/B testing (e.g.
		 * "commit-draft-assist-v1"). May be null for older results.
		 */
		String promptVersion) {

	/**
	 * Backwards-compatible constructor for callers that do not yet provide a prompt
	 * version.
	 */
	public AiSuggestionResult(boolean available, String payload, String rationale, double confidence,
			String modelVersion) {
		this(available, payload, rationale, confidence, modelVersion, null);
	}

	/** Convenience factory for an unavailable (degraded) result. */
	public static AiSuggestionResult unavailable() {
		return new AiSuggestionResult(false, "{}", "AI provider unavailable", 0.0, "none", null);
	}
}

/**
 * AI API client functions for all AI-powered endpoints.
 */
import type { ApiClient } from "./client.js";

// ── Types ─────────────────────────────────────────────────────────────────────

export interface AiStatusResponse {
  aiEnabled: boolean;
  providerName: string;
  providerVersion: string;
  available: boolean;
}

export interface CommitDraftAssistRequest {
  userId: string;
  planId: string;
  commitId?: string | undefined;
  currentTitle: string;
  currentDescription?: string | undefined;
  currentSuccessCriteria?: string | undefined;
  currentEstimatePoints?: number | undefined;
  chessPiece?: string | undefined;
}

export interface CommitDraftAssistResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  suggestedTitle?: string | null;
  suggestedDescription?: string | null;
  suggestedSuccessCriteria?: string | null;
  suggestedEstimatePoints?: number | null;
  /** Suggested chess piece. Non-null only when chessPiece was absent in the request. */
  suggestedChessPiece?: string | null;
  rationale?: string;
}

export interface CommitLintRequest {
  userId: string;
  planId: string;
}

export interface LintMessage {
  code: string;
  message: string;
  commitId?: string;
}

export interface CommitLintResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  hardValidation: LintMessage[];
  softGuidance: LintMessage[];
  rationale?: string;
}

export interface RiskSignal {
  id: string;
  signalType: string;
  rationale: string;
  planId: string;
  commitId?: string | null;
  createdAt: string;
}

export interface PlanRiskSignalsResponse {
  aiAvailable: boolean;
  planId: string;
  signals: RiskSignal[];
}

// ── Reconcile Assist types ─────────────────────────────────────────────────

export interface ReconcileAssistRequest {
  planId: string;
  userId: string;
}

export interface CommitOutcomeSuggestion {
  commitId: string;
  commitTitle: string;
  suggestedOutcome: string;
  rationale: string;
}

export interface CarryForwardRecommendation {
  commitId: string;
  commitTitle: string;
  rationale: string;
}

export interface ReconcileAssistResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  likelyOutcomes: CommitOutcomeSuggestion[];
  draftSummary?: string | null;
  carryForwardRecommendations: CarryForwardRecommendation[];
}

// ── RCDO Suggest types ────────────────────────────────────────────────────────

export interface RcdoSuggestRequest {
  planId: string;
  userId: string;
  /** Commit title used for semantic matching (required). */
  title: string;
  description?: string | undefined;
  chessPiece?: string | undefined;
}

export interface RcdoSuggestResponse {
  aiAvailable: boolean;
  /** True when a high-confidence (≥ 0.7) match was found. */
  suggestionAvailable: boolean;
  /** Stored suggestion id (null when unavailable or below threshold). */
  suggestionId?: string | null;
  /** Suggested RCDO node id. */
  suggestedRcdoNodeId?: string | null;
  /** Display title of the suggested node. */
  rcdoTitle?: string | null;
  /** Confidence score [0.0, 1.0]. */
  confidence?: number;
  /** Human-readable rationale for the suggestion. */
  rationale?: string | null;
}

export type FeedbackAction = "ACCEPTED" | "DISMISSED" | "EDITED";

export interface AiFeedbackRequest {
  suggestionId: string;
  userId: string;
  action: FeedbackAction;
  notes?: string;
}

// ── Manager AI Summary types ──────────────────────────────────────────────────

export interface ManagerAiSummaryResponse {
  aiAvailable: boolean;
  /** Stored suggestion id for feedback (null when unavailable). */
  suggestionId?: string | null;
  teamId: string;
  weekStart: string;
  /** Prose summary of the team week. Null when aiAvailable=false. */
  summaryText?: string | null;
  /** RCDO branch titles with highest planned commitment this week. */
  topRcdoBranches: string[];
  /** Unresolved exception ids (cited objects). */
  unresolvedExceptionIds: string[];
  /** Textual carry-forward patterns (cited from plan data). */
  carryForwardPatterns: string[];
  /** Work item ids for King/Queen commits currently BLOCKED (cited objects). */
  criticalBlockedItemIds: string[];
  modelVersion?: string | null;
}

// ── API factory ───────────────────────────────────────────────────────────────

export function createAiApi(client: ApiClient, actorUserId: string) {
  const actorHeader = { "X-Actor-User-Id": actorUserId };

  return {
    /** GET /api/ai/status — provider health/availability check. */
    getStatus: (): Promise<AiStatusResponse> =>
      client.get("/ai/status"),

    /** POST /api/ai/commit-draft-assist — get draft improvement suggestions. */
    commitDraftAssist: (
      request: CommitDraftAssistRequest,
    ): Promise<CommitDraftAssistResponse> =>
      client.post("/ai/commit-draft-assist", request),

    /**
     * Convenience helper for freeform "describe → structure" commit creation.
     * Sends the freeform text as currentTitle and omits chessPiece so the backend
     * can infer suggestedChessPiece.
     */
    commitFromFreeform: (
      planId: string,
      userId: string,
      freeformText: string,
    ): Promise<CommitDraftAssistResponse> =>
      client.post("/ai/commit-draft-assist", {
        planId,
        userId,
        currentTitle: freeformText,
      }),

    /** POST /api/ai/commit-lint — run commit quality lint on a plan. */
    commitLint: (request: CommitLintRequest): Promise<CommitLintResponse> =>
      client.post("/ai/commit-lint", request),

    /** GET /api/plans/{id}/risk-signals — risk signals for a plan. */
    getRiskSignals: (planId: string): Promise<PlanRiskSignalsResponse> =>
      client.get(`/plans/${encodeURIComponent(planId)}/risk-signals`, {
        headers: actorHeader,
      }),

    /** POST /api/ai/reconcile-assist — get reconciliation suggestions. */
    reconcileAssist: (
      request: ReconcileAssistRequest,
    ): Promise<ReconcileAssistResponse> =>
      client.post("/ai/reconcile-assist", request),

    /** POST /api/ai/feedback — record thumbs up/down on a suggestion. */
    recordFeedback: (request: AiFeedbackRequest): Promise<void> =>
      client.post("/ai/feedback", request),

    /**
     * POST /api/ai/rcdo-suggest — suggest a primary RCDO node for a commit
     * being authored. Only returns a suggestion when confidence ≥ 0.7.
     * Never auto-links — caller must present and allow user to accept/dismiss.
     */
    rcdoSuggest: (request: RcdoSuggestRequest): Promise<RcdoSuggestResponse> =>
      client.post("/ai/rcdo-suggest", request),

    /**
     * GET /api/teams/{id}/week/{weekStart}/ai-summary —
     * AI-generated manager team summary for the given team and week.
     *
     * @param teamId    team UUID string
     * @param weekStart ISO date string (YYYY-MM-DD) for the Monday of the week
     */
    getTeamAiSummary: (
      teamId: string,
      weekStart: string,
    ): Promise<ManagerAiSummaryResponse> =>
      client.get(
        `/teams/${encodeURIComponent(teamId)}/week/${encodeURIComponent(weekStart)}/ai-summary`,
        { headers: actorHeader },
      ),
  };
}

export type AiApi = ReturnType<typeof createAiApi>;

/**
 * React hooks for AI API endpoints.
 */
import { useMemo, useState, useEffect, useRef } from "react";
import { useHostBridge } from "../host/HostProvider.js";
import { createApiClient } from "./client.js";
import { useQuery, type QueryState } from "./hooks.js";
import { createAiApi, type AiApi, type AiStatusResponse, type PlanRiskSignalsResponse, type ReconcileAssistResponse, type ManagerAiSummaryResponse } from "./aiApi.js";
import { createWhatIfApi, type WhatIfApi } from "./whatIfApi.js";

/** Returns a stable WhatIfApi instance bound to the current user's auth token. */
export function useWhatIfApi(): WhatIfApi {
  const bridge = useHostBridge();
  const { authToken, authenticatedUser } = bridge.context;
  return useMemo(() => {
    const client = createApiClient({
      baseUrl: "/api",
      getAuthToken: () => bridge.context.authToken,
    });
    return createWhatIfApi(client, authenticatedUser.id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [authToken, authenticatedUser.id]);
}

/** Returns a stable AiApi instance bound to the current user's auth token. */
export function useAiApi(): AiApi {
  const bridge = useHostBridge();
  const { authToken, authenticatedUser } = bridge.context;
  return useMemo(() => {
    const client = createApiClient({
      baseUrl: "/api",
      getAuthToken: () => bridge.context.authToken,
    });
    return createAiApi(client, authenticatedUser.id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [authToken, authenticatedUser.id]);
}

/** Fetches the AI provider status. */
export function useAiStatus(): QueryState<AiStatusResponse> {
  const api = useAiApi();
  return useQuery<AiStatusResponse>("ai-status", () => api.getStatus());
}

/** Fetches risk signals for a specific plan. */
export function useRiskSignals(
  planId: string | null,
): QueryState<PlanRiskSignalsResponse> {
  const api = useAiApi();
  return useQuery<PlanRiskSignalsResponse>(
    `risk-signals-${planId ?? "none"}`,
    () => {
      if (!planId) return Promise.reject(new Error("No plan ID"));
      return api.getRiskSignals(planId);
    },
    { enabled: planId != null },
  );
}

/**
 * Fetches the AI-generated manager team summary for the given team and week.
 *
 * @param teamId    team UUID string, or `null` to skip fetching
 * @param weekStart ISO date string (YYYY-MM-DD)
 */
export function useManagerAiSummary(
  teamId: string | null,
  weekStart: string,
): QueryState<ManagerAiSummaryResponse> {
  const api = useAiApi();
  return useQuery<ManagerAiSummaryResponse>(
    `manager-ai-summary-${teamId ?? "none"}-${weekStart}`,
    () => {
      if (!teamId) return Promise.reject(new Error("No team ID"));
      return api.getTeamAiSummary(teamId, weekStart);
    },
    { enabled: teamId != null },
  );
}

/**
 * Auto-fetches AI reconciliation suggestions when a plan enters RECONCILING
 * state. Runs once per planId (tracked by ref). Falls back silently if AI
 * is unavailable — callers must handle `data === undefined`.
 *
 * @param planId       Plan UUID string, or null/undefined when not yet known.
 * @param userId       Authenticated user ID for the reconcile-assist request.
 * @param enabled      Set to `true` only when the plan is in RECONCILING state.
 */
export function useAutoReconcileAssist(
  planId: string | null | undefined,
  userId: string,
  enabled: boolean,
): { data: ReconcileAssistResponse | undefined; loading: boolean; error: string | null } {
  const aiApi = useAiApi();
  const [data, setData] = useState<ReconcileAssistResponse | undefined>(undefined);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  // Track which planId we've already fetched for so we don't re-fetch on re-renders.
  const fetchedForRef = useRef<string | null>(null);

  useEffect(() => {
    if (!enabled || !planId) return;
    if (fetchedForRef.current === planId) return;
    fetchedForRef.current = planId;

    let cancelled = false;
    setLoading(true);
    setError(null);

    aiApi
      .reconcileAssist({ planId, userId })
      .then((response) => {
        if (cancelled) return;
        if (response.aiAvailable) {
          setData(response);
        }
        setLoading(false);
      })
      .catch(() => {
        if (cancelled) return;
        // Graceful silent fallback — AI unavailable or errored.
        setError("AI suggestions unavailable");
        setLoading(false);
      });

    return () => {
      cancelled = true;
    };
    // aiApi is a new object each render but is memoised inside useAiApi by authToken.
    // Intentionally omitting it from deps to avoid re-fetching on unrelated renders.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [planId, userId, enabled]);

  return { data, loading, error };
}

package com.weeklycommit.domain.entity;

import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.persistence.Table;
import jakarta.validation.constraints.NotBlank;
import java.time.Instant;
import java.time.LocalDate;
import java.util.UUID;
import org.hibernate.annotations.ColumnTransformer;
import org.hibernate.annotations.CreationTimestamp;

@Entity
@Table(name = "ai_suggestion")
public class AiSuggestion {

	@Id
	@GeneratedValue(strategy = GenerationType.UUID)
	@Column(nullable = false, updatable = false)
	private UUID id;

	@Column(name = "user_id")
	private UUID userId;

	@Column(name = "plan_id")
	private UUID planId;

	@Column(name = "commit_id")
	private UUID commitId;

	@Column(name = "context_hash")
	private String contextHash;

	@Column(name = "team_id")
	private UUID teamId;

	@Column(name = "week_start_date")
	private LocalDate weekStartDate;

	@NotBlank
	@Column(name = "suggestion_type", nullable = false)
	private String suggestionType;

	@NotBlank
	@Column(nullable = false, columnDefinition = "text")
	private String prompt;

	@NotBlank
	@Column(nullable = false, columnDefinition = "text")
	private String rationale;

	@NotBlank
	@ColumnTransformer(write = "?::jsonb")
	@Column(name = "suggestion_payload", nullable = false, columnDefinition = "jsonb")
	private String suggestionPayload;

	@NotBlank
	@Column(name = "model_version", nullable = false)
	private String modelVersion;

	@Column
	private Boolean accepted;

	@Column
	private Boolean dismissed;

	@Column(name = "prompt_version")
	private String promptVersion;

	@Column(name = "eval_faithfulness_score")
	private Float evalFaithfulnessScore;

	@Column(name = "eval_relevancy_score")
	private Float evalRelevancyScore;

	@Column(name = "eval_scored_at")
	private Instant evalScoredAt;

	@CreationTimestamp
	@Column(name = "created_at", nullable = false, updatable = false)
	private Instant createdAt;

	public UUID getId() {
		return id;
	}

	public void setId(UUID id) {
		this.id = id;
	}

	public UUID getUserId() {
		return userId;
	}

	public void setUserId(UUID userId) {
		this.userId = userId;
	}

	public UUID getPlanId() {
		return planId;
	}

	public void setPlanId(UUID planId) {
		this.planId = planId;
	}

	public UUID getCommitId() {
		return commitId;
	}

	public void setCommitId(UUID commitId) {
		this.commitId = commitId;
	}

	public String getSuggestionType() {
		return suggestionType;
	}

	public void setSuggestionType(String suggestionType) {
		this.suggestionType = suggestionType;
	}

	public String getPrompt() {
		return prompt;
	}

	public void setPrompt(String prompt) {
		this.prompt = prompt;
	}

	public String getRationale() {
		return rationale;
	}

	public void setRationale(String rationale) {
		this.rationale = rationale;
	}

	public String getSuggestionPayload() {
		return suggestionPayload;
	}

	public void setSuggestionPayload(String suggestionPayload) {
		this.suggestionPayload = suggestionPayload;
	}

	public String getModelVersion() {
		return modelVersion;
	}

	public void setModelVersion(String modelVersion) {
		this.modelVersion = modelVersion;
	}

	public Boolean getAccepted() {
		return accepted;
	}

	public void setAccepted(Boolean accepted) {
		this.accepted = accepted;
	}

	public Boolean getDismissed() {
		return dismissed;
	}

	public void setDismissed(Boolean dismissed) {
		this.dismissed = dismissed;
	}

	public String getContextHash() {
		return contextHash;
	}

	public void setContextHash(String contextHash) {
		this.contextHash = contextHash;
	}

	public UUID getTeamId() {
		return teamId;
	}

	public void setTeamId(UUID teamId) {
		this.teamId = teamId;
	}

	public LocalDate getWeekStartDate() {
		return weekStartDate;
	}

	public void setWeekStartDate(LocalDate weekStartDate) {
		this.weekStartDate = weekStartDate;
	}

	public Instant getCreatedAt() {
		return createdAt;
	}

	public String getPromptVersion() {
		return promptVersion;
	}

	public void setPromptVersion(String promptVersion) {
		this.promptVersion = promptVersion;
	}

	public Float getEvalFaithfulnessScore() {
		return evalFaithfulnessScore;
	}

	public void setEvalFaithfulnessScore(Float evalFaithfulnessScore) {
		this.evalFaithfulnessScore = evalFaithfulnessScore;
	}

	public Float getEvalRelevancyScore() {
		return evalRelevancyScore;
	}

	public void setEvalRelevancyScore(Float evalRelevancyScore) {
		this.evalRelevancyScore = evalRelevancyScore;
	}

	public Instant getEvalScoredAt() {
		return evalScoredAt;
	}

	public void setEvalScoredAt(Instant evalScoredAt) {
		this.evalScoredAt = evalScoredAt;
	}
}

